#include<iostream>
#include<vector>
using namespace std;

double findPrice(double test, double w, double b) {
    return (test*w + b);
}

void gradient_descent(vector<double>x_inputs, vector<double>y_inputs, double alpha, int iterations,double& w, double& b) {
   
    for(int i=0;i<iterations;i++) {
        double d_w=0;
        double d_b=0;
        
        int m=x_inputs.size();
        
        double error;
        for(int j=0;j<m;j++) {
            error=(findPrice(x_inputs[j],w,b)-y_inputs[j]);
            
            d_w+=(error)*x_inputs[j];
            d_b+=error;
        }

        d_w=d_w/m;
        d_b=d_b/m;

        w=w-(d_w)*alpha;
        b=b-(d_b)*alpha;

        if(i%1000==0) {
            cout<<"Iteration = "<<i<<endl;
            cout<<"w= "<<w<<" b= "<<b<<endl;
        }
    }        
}


